#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define MAX 1000000

long long dp[100][100];

long long minSandwiches(long long n, long long k, long long m) {
    if (n <= k) return 1;
    if (n < 0) return 0;
    if (dp[n][k] != -1) return dp[n][k];
    long long ans = 0;
    for (long long i = 1; i <= k; i++) {
        ans = (ans + minSandwiches(n - i, k, m)) % m;
    }
    return dp[n][k] = ans;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        long long n, k, m;
        scanf("%lld %lld %lld", &n, &k, &m);
        memset(dp, -1, sizeof(dp));
        long long ans = minSandwiches(n, k, m);
        printf("%lld %lld\n", (n + k - 1) / k, ans);
    }
    return 0;
}

